void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 wraps each migration in its own transaction;
    // calling Migrate() inside a user transaction now throws.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

