using Microsoft.EntityFrameworkCore;

// Cosmos DB provider – EF Core 9 breaking-change fixes
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1 – Discriminator property name changed from "Discriminator" to "$type" in EF Core 9.
        // Existing documents already store "Discriminator", so pin the old name to avoid
        // data loss / query failures on existing containers.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");
    }

    // FIX 2 – Synchronous Cosmos DB queries removed in EF Core 9.
    // All calls such as ToList(), First(), Single(), Count() must become async.

    // BEFORE (EF Core 8 – now throws InvalidOperationException):
    //   List<Product> GetAll(CosmosDbContext db)
    //       => db.Products.ToList();

    // AFTER (EF Core 9):
    async Task<List<Product>> GetAllAsync(CosmosDbContext db)
        => await db.Products.ToListAsync();
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

